package control_session;

public class five_eleven {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int num=555555;
		if(num%5==0 && num%11==0)
		{
			System.out.println("the given number is divisible by 5 and 11");
		}
		else System.out.println("the given number is not divisible by 5 and 11");
	}

}
